section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/api-contract-pattern-selection.json",
  "title": "API Contract Pattern Selection",
  "type": "object",
  "required": [
    "artefact_id",
    "api_id",
    "consumer_count",
    "tooling_needs",
    "evolution_rate",
    "team_boundary",
    "verdict",
    "rationale",
    "status",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "api_id": {
      "type": "string",
      "description": "service id or repo slug the API lives in",
      "minLength": 1
    },
    "consumer_count": {
      "type": "integer",
      "description": "number of distinct callers expected within 12mo"
    },
    "tooling_needs": {
      "type": "array",
      "description": "list of required tools (sdk-gen, mock-server, doc-portal, contract-test)",
      "minItems": 1
    },
    "evolution_rate": {
      "type": "string",
      "description": "low|medium|high (expected breaking changes per quarter)",
      "minLength": 1
    },
    "team_boundary": {
      "type": "string",
      "description": "single-team|cross-team|external",
      "minLength": 1
    },
    "verdict": {
      "type": "string",
      "description": "openapi-3.1|graphql-sdl|trpc|json-rpc|grpc|none-internal-only",
      "minLength": 1
    },
    "rationale": {
      "type": "string",
      "description": "one-paragraph justification linking the answers to the verdict",
      "minLength": 1
    }
  },
  "additionalProperties": false
}
